185: 	s.logger.Info("GRPC server: initiating graceful shutdown")
186: 	gracefulStopDone := make(chan struct{})
187: 	go func() {
188: 		s.server.GracefulStop()
189: 		close(gracefulStopDone)
190: 	}()
